// Merge all RSS feeds into single array
const allItems = [];

// Helper to safely extract items from various RSS formats
const extractItems = (response, source) => {
  if (!response) return [];

  // Handle different RSS structures
  let items = [];

  if (Array.isArray(response)) {
    items = response;
  } else if (response.items && Array.isArray(response.items)) {
    items = response.items;
  } else if (response.feed && response.feed.items) {
    items = response.feed.items;
  } else if (typeof response === 'object') {
    // Try common RSS item paths
    for (const key of Object.keys(response)) {
      const val = response[key];
      if (Array.isArray(val) && val.length > 0 && (val[0].title || val[0].link)) {
        items = val;
        break;
      }
    }
  }

  return items.map(item => ({
    ...item,
    _source: source
  }));
};

// Process each input
const inputs = $input.all();
for (const input of inputs) {
  if (input.json && input.json.length !== undefined) {
    // Array of items
    allItems.push(...input.json.map(item => ({ ...item, _source: input.json._source || 'unknown' })));
  } else if (input.json) {
    allItems.push(...extractItems(input.json, input.json._source || 'unknown'));
  }
}

// If no items from inputs, try to parse from first response
if (allItems.length === 0 && inputs.length > 0) {
  const firstData = inputs[0].json;
  if (firstData && firstData.items) {
    allItems.push(...firstData.items.map(item => ({ ...item, _source: 'merged' })));
  }
}

return allItems.map(item => ({ json: item }));

// Filter and classify news items
const twoHoursAgo = new Date(Date.now() - 2 * 60 * 60 * 1000);

const HIGH_PRIORITY_KEYWORDS = [
  'Fed', 'FOMC', 'interest rate', 'inflation', 'CPI', 'NFP', 'unemployment',
  'oil', 'crude', 'OPEC', 'Iran', 'Russia', 'Ukraine', 'China', 'Taiwan',
  'sanctions', 'war', 'attack', 'missile', 'nuclear', 'Bitcoin', 'crypto',
  'SEC', 'ETF', 'recession', 'GDP', 'PMI', 'ECB', 'BOE', 'BOJ',
  'Dollar', 'DXY', 'EUR', 'JPY', 'gold', 'silver'
];

const CRITICAL_GEOPOLITICAL = [
  'war', 'attack', 'invasion', 'nuclear', 'sanctions', 'embargo', 'conflict',
  'missile', 'explosion', 'coup'
];

const CATEGORY_KEYWORDS = {
  macro: ['Fed', 'FOMC', 'interest rate', 'inflation', 'CPI', 'NFP', 'unemployment', 'GDP', 'PMI', 'ECB', 'BOE', 'BOJ', 'recession', 'Dollar', 'DXY'],
  geopolitica: ['war', 'attack', 'invasion', 'sanctions', 'embargo', 'conflict', 'coup', 'Russia', 'Ukraine', 'China', 'Taiwan', 'Iran', 'missile', 'explosion'],
  energia: ['oil', 'crude', 'OPEC', 'EIA', 'energy', 'gas', 'petroleum', 'natural gas'],
  crypto: ['Bitcoin', 'crypto', 'SEC', 'ETF', 'blockchain', 'coin', 'token', 'Bitcoin ETF'],
  divisas: ['EUR', 'JPY', 'GBP', 'USD', 'forex', 'currency', 'exchange rate']
};

const ASSET_KEYWORDS = {
  CL: ['oil', 'crude', 'OPEC', 'petroleum'],
  ES: ['S&P', 'equity', 'stock', 'SP500'],
  NQ: ['Nasdaq', 'tech', 'stock'],
  GC: ['gold', 'gold futures', 'XAU'],
  SI: ['silver', 'XAG'],
  NG: ['natural gas', 'energy'],
  BTC: ['Bitcoin', 'crypto', 'BTC'],
  ETH: ['Ethereum', 'ETH', 'crypto'],
  XAUUSD: ['gold', 'XAU'],
  XAGUSD: ['silver', 'XAG']
};

function matchesKeywords(text, keywords) {
  if (!text) return false;
  const lower = text.toLowerCase();
  return keywords.some(kw => lower.includes(kw.toLowerCase()));
}

function getCategory(title, description) {
  const text = `${title || ''} ${description || ''}`;
  for (const [cat, keywords] of Object.entries(CATEGORY_KEYWORDS)) {
    if (matchesKeywords(text, keywords)) return cat;
  }
  return 'macro';
}

function getAffectedAssets(title, description) {
  const text = `${title || ''} ${description || ''}`;
  const assets = [];
  for (const [asset, keywords] of Object.entries(ASSET_KEYWORDS)) {
    if (matchesKeywords(text, keywords)) assets.push(asset);
  }
  return assets.length > 0 ? assets : ['GENERAL'];
}

function parseDate(item) {
  const dateStr = item.pubDate || item.date || item.updated || item.published;
  if (!dateStr) return new Date();
  try {
    return new Date(dateStr);
  } catch {
    return new Date();
  }
}

function extractGuid(item) {
  return item.guid || item.link || item.id || `${item.title}-${item.pubDate}`;
}

function truncate(text, maxLen) {
  if (!text) return '';
  const clean = text.replace(/<[^>]*>/g, '').trim();
  return clean.length > maxLen ? clean.substring(0, maxLen) + '...' : clean;
}

const items = $input.all();
const filteredItems = [];

for (const itemWrapper of items) {
  const item = itemWrapper.json;

  try {
    // Parse date
    const pubDate = parseDate(item);

    // Skip if older than 2 hours
    if (pubDate < twoHoursAgo) continue;

    // Combine title and description for keyword matching
    const title = item.title || '';
    const description = item.description || item.content || '';
    const fullText = `${title} ${description}`;

    // Check for high priority keywords
    const isHighPriority = matchesKeywords(fullText, HIGH_PRIORITY_KEYWORDS);
    if (!isHighPriority) continue;

    // Check for critical geopolitical
    const isCritical = matchesKeywords(fullText, CRITICAL_GEOPOLITICAL);

    // Build result object
    const result = {
      timestamp: pubDate.toISOString(),
      titulo: title,
      fuente: item._source || 'unknown',
      url: item.link || item.url || '',
      categoria: getCategory(title, description),
      urgencia: isCritical ? 'alta' : (isHighPriority ? 'alta' : 'media'),
      activos_afectados: getAffectedAssets(title, description),
      resumen: truncate(description, 200),
      guid: extractGuid(item),
      is_critical_geopolitical: isCritical
    };

    filteredItems.push(result);
  } catch (error) {
    // Skip malformed items
    console.error('Error processing item:', error);
  }
}

// Sort by timestamp descending
filteredItems.sort((a, b) => new Date(b.timestamp) - new Date(a.timestamp));

return filteredItems.map(item => ({ json: item }));

// Deduplicate against news_seen.json
const fs = require('fs');
const path = require('path');

const seenFilePath = '/data/cache/news_seen.json';
const seenGuids = new Set();

// Load existing seen GUIDs
try {
  if (fs.existsSync(seenFilePath)) {
    const data = fs.readFileSync(seenFilePath, 'utf8');
    const seen = JSON.parse(data);
    // Support both array and object formats
    if (Array.isArray(seen)) {
      seen.forEach(guid => seenGuids.add(guid));
    } else if (seen.guids && Array.isArray(seen.guids)) {
      seen.guids.forEach(guid => seenGuids.add(guid));
    }
  }
} catch (error) {
  console.error('Error reading seen file:', error.message);
}

// Filter out duplicates
const items = $input.all();
const deduplicated = [];
const newGuids = [];

for (const itemWrapper of items) {
  const item = itemWrapper.json;
  const guid = item.guid || item.url || `${item.titulo}-${item.timestamp}`;

  if (!seenGuids.has(guid)) {
    deduplicated.push(item);
    newGuids.push(guid);
  }
}

// Update seen file with today's GUIDs
try {
  const today = new Date().toISOString().split('T')[0];
  const existingData = { date: today, guids: [] };

  if (fs.existsSync(seenFilePath)) {
    const existing = JSON.parse(fs.readFileSync(seenFilePath, 'utf8'));
    if (existing.date === today) {
      existingData.guids = existing.guids || [];
    }
  }

  existingData.guids = [...existingData.guids, ...newGuids];

  // Ensure directory exists
  const dir = path.dirname(seenFilePath);
  if (!fs.existsSync(dir)) {
    fs.mkdirSync(dir, { recursive: true });
  }

  fs.writeFileSync(seenFilePath, JSON.stringify(existingData, null, 2));
} catch (error) {
  console.error('Error writing seen file:', error.message);
}

return deduplicated.map(item => ({ json: item }));

// Store news_feed.json and prepare alerts
const fs = require('fs');
const path = require('path');

const feedFilePath = '/data/cache/news_feed.json';
const maxItems = 100;

const items = $input.all();

// Read existing feed
let existingFeed = [];
try {
  if (fs.existsSync(feedFilePath)) {
    existingFeed = JSON.parse(fs.readFileSync(feedFilePath, 'utf8'));
  }
} catch (error) {
  console.error('Error reading feed file:', error.message);
}

// Merge and rotate
const mergedFeed = [...items.map(i => i.json), ...existingFeed]
  .slice(0, maxItems);

// Ensure directory exists
const dir = path.dirname(feedFilePath);
if (!fs.existsSync(dir)) {
  fs.mkdirSync(dir, { recursive: true });
}

// Write updated feed
try {
  fs.writeFileSync(feedFilePath, JSON.stringify(mergedFeed, null, 2));
} catch (error) {
  console.error('Error writing feed file:', error.message);
}

// Return items with alert flag for high urgency
return items.map(item => ({
  json: {
    ...item.json,
    send_alert: item.json.urgencia === 'alta' || item.json.is_critical_geopolitical
  }
}));

// Filter for GET /webhook/news-latest - last 20 news
const fs = require('fs');

const feedFilePath = '/data/cache/news_feed.json';

try {
  if (fs.existsSync(feedFilePath)) {
    const feed = JSON.parse(fs.readFileSync(feedFilePath, 'utf8'));
    const latest = feed.slice(0, 20);
    return latest.map(item => ({ json: item }));
  }
} catch (error) {
  console.error('Error reading feed:', error.message);
}

return [{ json: { news: [], count: 0, error: 'No feed data available' } }];

// Filter for GET /webhook/news-urgent - today's high urgency
const fs = require('fs');

const feedFilePath = '/data/cache/news_feed.json';
const today = new Date().toISOString().split('T')[0];

try {
  if (fs.existsSync(feedFilePath)) {
    const feed = JSON.parse(fs.readFileSync(feedFilePath, 'utf8'));
    const urgent = feed.filter(item => {
      const itemDate = item.timestamp ? item.timestamp.split('T')[0] : '';
      return itemDate === today && item.urgencia === 'alta';
    });
    return urgent.map(item => ({ json: item }));
  }
} catch (error) {
  console.error('Error reading feed:', error.message);
}

return [{ json: { news: [], count: 0, error: 'No urgent news available' } }];
